import React from 'react';
import PropTypes from 'prop-types';
import { Link } from 'react-router';
import { prefixLink } from 'gatsby-helpers';
import Helmet from 'react-helmet';
import { config } from 'config';
import { rhythm } from '../utils/typography';
import 'tachyons/css/tachyons.min.css';

export default class Template extends React.Component {
  static propTypes = {
    children: PropTypes.any,
  };

  render() {
    return (
      <div>
        <Helmet
          title={config.siteTitle}
          meta={[
            { name: 'description', content: 'Sample' },
            { name: 'keywords', content: 'sample, something' },
          ]}
        />
        <header className="tc pv3 pv4-ns bb b--light-gray">
          <h1 className="f6 f4-ns fw6 mid-gray">
            <Link to={prefixLink('/')} className="link black">
              Can Uzunoğlu
            </Link>
          </h1>
          <h2 className="f7 gray fw2 ttu tracked">
            FRONT-END DEVELOPER / ISTANBUL
          </h2>
        </header>
        <section className="mw5 mw7-ns center pa3 ph5-ns">
          {this.props.children}
        </section>
      </div>
    );
  }
}



